async function resolveCustomSkillsForAgent(admin, customerId, agentSkills) {
  if (agentSkills.length === 0) return [];
  const customSlugs = agentSkills.filter((s) => s.startsWith("custom:")).map((s) => s.slice(7));
  if (customSlugs.length === 0) return [];
  const { data, error } = await admin.from("custom_skills").select("slug, name, content").eq("customer_id", customerId).eq("status", "active").in("slug", customSlugs);
  if (error || !data) return [];
  return data.map((row) => ({
    slug: row.slug,
    name: row.name,
    body: stripFrontmatter(row.content || "")
  }));
}
